set -euo pipefail
TENANT_ID='{{$node['Normalize Repair Input'].json.tenant_id}}'
JOB_ID='{{$node['Normalize Repair Input'].json.job_id}}'
PATH_IN='{{$node['Normalize Repair Input'].json.job_runtime_path}}'
FAILED_STAGE='{{$node['Normalize Repair Input'].json.failed_stage}}'
ATTEMPT='{{$node['Normalize Repair Input'].json.attempt}}'
DEFECT='{{$node['Normalize Repair Input'].json.defect_report}}'
REQUEST_JSON='{{$node['Normalize Repair Input'].json.request_json}}'
NOW='$(date -u +%Y-%m-%dT%H:%M:%SZ)'
export TENANT_ID JOB_ID PATH_IN FAILED_STAGE ATTEMPT DEFECT REQUEST_JSON NOW
node <<'NODE'
const fs = require('fs');
const tenantId = process.env.TENANT_ID;
const jobId = process.env.JOB_ID;
const pathIn = process.env.PATH_IN;
const stage = process.env.FAILED_STAGE;
const attempt = Number(process.env.ATTEMPT || 1);
const defectInput = process.env.DEFECT || '';
const req = JSON.parse(process.env.REQUEST_JSON || '{}');
const now = process.env.NOW;
const maxAttempts = 3;
const doc = JSON.parse(fs.readFileSync(pathIn, 'utf8'));
doc.status_updates = Array.isArray(doc.status_updates) ? doc.status_updates : [];
doc.defect_reports = Array.isArray(doc.defect_reports) ? doc.defect_reports : [];
const push = (state, status, step, details) => doc.status_updates.push({ at: now, state, status, step, details });
push('repair_running', 'in_progress', 'repair_started', { attempt, failed_stage: stage });
push('stage_patching', 'in_progress', 'patch_failed_stage_section', { scope: 'only_failed_stage_section', stage });
doc.production = doc.production || {};
doc.production.parallel_branches = doc.production.parallel_branches || {};
const branch = doc.production.parallel_branches[stage] || {};
doc.production.parallel_branches[stage] = {
  ...branch,
  state: 'repair_patched',
  status: 'ready_for_rerun',
  last_patch: { at: now, attempt, patch_scope: 'only_failed_stage_section', defect_report: defectInput }
};
push('stage_rerun', 'in_progress', 'rerun_failed_stage_only', { scope: 'only_failed_stage', stage });
const rerunStatus = req.simulate_stage_failure ? 'fail' : 'pass';
if (rerunStatus === 'pass') {
  doc.production.parallel_branches[stage] = {
    ...doc.production.parallel_branches[stage],
    state: 'completed',
    status: 'success',
    last_rerun: { at: now, attempt, rerun_scope: 'only_failed_stage', result: 'pass' }
  };
  doc.state = 'completed';
  doc.status = 'success';
  push('completed', 'success', 'repair_completed', { stage, attempt });
} else {
  doc.production.parallel_branches[stage] = {
    ...doc.production.parallel_branches[stage],
    state: 'failed',
    status: 'failed',
    last_rerun: { at: now, attempt, rerun_scope: 'only_failed_stage', result: 'fail' }
  };
  const defect = {
    at: now,
    attempt,
    stage,
    code: 'stage_rerun_failed',
    message: 'Failed stage rerun after bounded patch',
    evidence: {
      rerun_scope: 'only_failed_stage',
      patch_scope: 'only_failed_stage_section',
      input_defect_report: defectInput || null
    }
  };
  doc.defect_reports.push(defect);
  if (attempt < maxAttempts) {
    doc.state = 'awaiting_retry';
    doc.status = 'retry_scheduled';
    push('awaiting_retry', 'pending', 'retry_remaining', { attempt, next_attempt: attempt + 1, max_attempts: maxAttempts });
  } else {
    doc.state = 'failed';
    doc.status = 'failed';
    push('failed', 'failed', 'max_attempts_reached', { attempt, max_attempts: maxAttempts });
  }
}
doc.attempt = attempt;
doc.max_attempts = maxAttempts;
doc.updated_at = now;
doc.history = doc.status_updates;
fs.writeFileSync(pathIn, JSON.stringify(doc, null, 2));
const out = {
  status: rerunStatus === 'pass' ? 'pass' : 'fail',
  tenant_id: tenantId,
  job_id: jobId,
  job_runtime_path: pathIn,
  failed_stage: stage,
  attempt,
  job_state: doc.state,
  patched_section: 'production.parallel_branches.' + stage,
  rerun_scope: 'only_failed_stage',
  max_attempts: maxAttempts,
  max_attempts_reached: rerunStatus === 'fail' && attempt >= maxAttempts,
  status_updates: doc.status_updates,
  defect_reports: doc.defect_reports
};
process.stdout.write(JSON.stringify(out));
NODE

